final:
module top_module(
  output reg [2:0] cycle,
  input clk,
  input enn
);reg [2:0] counter_value = 3'b000;

  always @(posedge clk) begin
    if(!enn)
      counter_value <= (counter_value == 3'b111) ? 3'b000 : counter_value + 1;
    else
      counter_value <= 3'b000;
  end

  assign cycle = counter_value;

endmodule
